const webhookData = $('Webhook Recebe Rota').item.json.body || {};
const configData = $('Ler Configuração DL Nexus').item.json || {};
const mapsData = $input.all()[0].json || {};

if (!webhookData.origem || !webhookData.destino) {
    return { json: {
        status: "Sob Avaliação Técnica",
        mensagem: "Origem ou destino não fornecidos. Aguardando Avaliação Técnica."
    }};
}

const precoCombustivel = configData.preco_combustivel || 7.80;
const consumoVeiculo = configData.km_por_litro || 16;

let distanciaMeters = 0;
let durationText = 'N/A';

let element = {};
if (mapsData.rows && mapsData.rows[0] && mapsData.rows[0].elements && mapsData.rows[0].elements[0]) {
    element = mapsData.rows[0].elements[0];
} else {
    element = mapsData;
}

if (element.distance && element.distance.value) {
    distanciaMeters = element.distance.value;
}
if (element.duration && element.duration.text) {
    durationText = element.duration.text;
}

let distanciaKm = distanciaMeters / 1000;
if (distanciaKm === 0) {
    return { json: {
        status: "Sob Avaliação Técnica",
        mensagem: "Não foi possível calcular a rota via Maps. Aguardando Avaliação Técnica."
    }};
}

let zona = (webhookData.zona || '').toLowerCase();
let custoEstacionamento = 0;

if (zona.includes('zona sul')) {
    custoEstacionamento = 45;
} else if (zona.includes('barra')) {
    custoEstacionamento = 30;
} else if (zona.includes('centro')) {
    custoEstacionamento = 40;
} else {
    custoEstacionamento = 20;
}

let fatorUrgencia = 1.0;
let escopo = (webhookData.escopo || '').toLowerCase();
if (escopo.includes('chapa') || escopo.includes('fritadeira') || escopo.includes('gastronomia')) {
    fatorUrgencia = 1.5;
}

let custoDeslocamentoBruto = (distanciaKm / consumoVeiculo) * precoCombustivel;
let custoTotalInterno = (custoDeslocamentoBruto + custoEstacionamento) * fatorUrgencia;

let precoRecomendado = custoTotalInterno * 2.5;

return { json: {
    status: "Sucesso",
    faixa_comercial: {
        minimo: parseFloat((precoRecomendado * 0.9).toFixed(2)),
        maximo: parseFloat((precoRecomendado * 1.1).toFixed(2))
    },
    preco_recomendado: parseFloat(precoRecomendado.toFixed(2)),
    imposto_estimado_percentual: "pendência de validação contábil",
    detalhes_operacionais: {
        distancia_km: parseFloat(distanciaKm.toFixed(2)),
        tempo_estimado: durationText,
        fator_multiplicador_aplicado: fatorUrgencia,
        sistema_gestao: "Fortress",
        responsavel: "Tecnólogo Responsável - Diogo"
    }
}};

